content.css:
.kpi-host {
  width: 100%;
  height: 100%;
  overflow: hidden;
  font-family: 'Inter', 'Segoe UI', -apple-system, BlinkMacSystemFont, sans-serif;
  font-size: 13px;
  color: #0E1525;
  -webkit-font-smoothing: antialiased;
  letter-spacing: -0.005em;
  background: transparent;
  padding: 6px;
  box-sizing: border-box;
}
.kpi-empty {
  color: #8A91A1;
  font-size: 12px;
  text-align: center;
  padding: 16px;
}
.kpi-card {
  --accent: #6366F1;
  --accent-soft: #EEF0FE;
  position: relative;
  width: 100%;
  height: 100%;
  padding: 12px 14px 0;
  border-radius: 14px;
  background: #FFFFFF;
  border: 1px solid #ECEEF3;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  box-sizing: border-box;
  transition: border-color 0.15s ease, box-shadow 0.15s ease;
}
.kpi-card:hover {
  border-color: #D7DBE4;
  box-shadow: 0 1px 3px rgba(15, 23, 42, 0.04), 0 4px 12px rgba(15, 23, 42, 0.04);
}
.kpi-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 6px;
}
.kpi-label {
  font-size: 11px;
  color: #8A91A1;
  font-weight: 500;
  letter-spacing: -0.005em;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  max-width: 70%;
}
.kpi-badge {
  width: 22px;
  height: 22px;
  border-radius: 6px;
  display: grid;
  place-items: center;
  color: #5E6677;
  background: #F8F9FC;
  flex-shrink: 0;
}
.kpi-badge.accent {
  color: var(--accent);
  background: var(--accent-soft);
}
.kpi-badge svg {
  display: block;
}
.kpi-value {
  font-size: 28px;
  font-weight: 700;
  letter-spacing: -0.03em;
  font-variant-numeric: tabular-nums;
  color: #0E1525;
  line-height: 1.05;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.kpi-row {
  display: flex;
  align-items: baseline;
  gap: 8px;
  margin-top: 4px;
}
.kpi-delta {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  font-size: 11px;
  font-weight: 600;
  padding: 1px 6px 1px 4px;
  border-radius: 5px;
  font-variant-numeric: tabular-nums;
  line-height: 1.4;
}
.kpi-delta svg {
  display: block;
}
.kpi-delta.pos {
  color: #0E9F6E;
  background: #E6F6EF;
}
.kpi-delta.neg {
  color: #DC2D4A;
  background: #FCE9EC;
}
.kpi-vs {
  font-size: 10.5px;
  color: #8A91A1;
}
.kpi-spark {
  height: 32px;
  margin: 6px -14px -1px;
  margin-top: auto;
  flex-shrink: 0;
}
.kpi-spark svg {
  width: 100%;
  height: 100%;
  display: block;
}
